function makeCounter() {
  let count = 0;               // private state, lives in the closure
  return {
    inc() { return ++count; },
    dec() { return --count; },
  };
}
const c = makeCounter();
console.log(c.inc(), c.inc(), c.dec()); // 1 2 1
console.log("count is private:", c.count); // undefined

// var shares ONE binding; let creates a fresh binding each iteration
const withVar = [];
for (var i = 0; i < 3; i++) withVar.push(() => i);
console.log("var:", withVar.map(f => f())); // [3, 3, 3]

const withLet = [];
for (let j = 0; j < 3; j++) withLet.push(() => j);
console.log("let:", withLet.map(f => f())); // [0, 1, 2]

const field = "role";
const id = 7;

const obj = {
  [field]: "admin",                 // variable as key
  ["item_" + id]: { qty: 2 },       // expression as key
  [`status_${id}`]: "active",       // template string as key
};
console.log(obj); // { role: "admin", item_7: {qty:2}, status_7: "active" }

// build a lookup map with reduce + computed key
const users = [{ id: 1, name: "Ada" }, { id: 2, name: "Lin" }];
const byId = users.reduce((acc, u) => ({ ...acc, [u.id]: u.name }), {});
console.log(byId); // { "1": "Ada", "2": "Lin" }

// math.js — named + default exports
export const add = (a, b) => a + b;
export const PI = 3.14159;
export default function multiply(a, b) { return a * b; }

// app.js — import them
import multiply, { add, PI } from "./math.js";
console.log(add(2, 3), PI, multiply(2, 4)); // 5 3.14159 8

// rename + namespace import
import { add as sum } from "./math.js";
import * as math from "./math.js";

// dynamic import for lazy code-splitting (returns a promise)
const { add: lazyAdd } = await import("./math.js");

class Counter {
  #count = 0;                  // truly private
  #step;
  constructor(step = 1) { this.#step = step; }
  inc() { this.#count += this.#step; return this.#count; }
  get value() { return this.#count; }
}

const c = new Counter(5);
console.log(c.inc(), c.inc());   // 5 10
console.log(c.value);            // 10

// private fields are invisible from outside
console.log(Object.keys(c));     // []
console.log(JSON.stringify(c));  // {}

class MathUtil {
  static PI = 3.14159;
  static square(n) { return n * n; }
}
console.log(MathUtil.PI, MathUtil.square(5)); // 3.14159 25
console.log(new MathUtil().square);            // undefined — not on instances

// static factory: 'this' is the class, so new this(...) works
class User {
  constructor(name) { this.name = name; }
  static fromJSON(json) { return new this(JSON.parse(json).name); }
}
const u = User.fromJSON('{"name":"Ada"}');
console.log(u.name);                           // "Ada"

function highlight(strings, ...values) {
  return strings.reduce((out, str, i) => {
    const v = i < values.length ? "[" + values[i] + "]" : "";
    return out + str + v;
  }, "");
}

const name = "Ada";
const score = 99;
console.log(highlight`User ${name} scored ${score}!`);
// → "User [Ada] scored [99]!"

// String.raw keeps escape sequences literal
console.log(String.raw`line1\nstill line1`); // "line1\nstill line1"

