o2.x = undefined;
console.log("x" in o2);        // true — key still exists!

// arrays: delete leaves a hole, length unchanged
const arr = ["a", "b", "c"];
delete arr[1];
console.log(arr, arr.length);  // ["a", <empty>, "c"]  3
console.log(arr[1]);            // undefined

