const nums = [1, 2, 3, 4, 5];

// HOFs that TAKE a function
const doubled = nums.map(n => n * 2);
const evens   = nums.filter(n => n % 2 === 0);
const sum     = nums.reduce((acc, n) => acc + n, 0);
console.log(doubled, evens, sum);  // [2,4,6,8,10] [2,4] 15

// A HOF that RETURNS a function (a decorator)
function withLogging(fn) {
  return function (...args) {
    console.log("calling with", args);
    const out = fn(...args);
    console.log("→ returned", out);
    return out;
  };
}
const add = withLogging((a, b) => a + b);
add(2, 3);  // logs the call, then "→ returned 5"

// PURE — depends only on input, returns a new value
function add(a, b) { return a + b; }
function addItem(cart, item) { return [...cart, item]; } // no mutation

console.log(add(2, 3));            // 3 → always 5... er, 5
console.log(add(2, 3));            // 5 again (deterministic)

const cart = ["apple"];
console.log(addItem(cart, "pear")); // ["apple","pear"]
console.log(cart);                  // ["apple"] — original untouched

// IMPURE — mutates external state, output depends on it
let total = 0;
function addToTotal(n) { total += n; return total; } // side effect
console.log(addToTotal(5)); // 5
console.log(addToTotal(5)); // 10 — same input, different output!

const counter = (function () {
  let count = 0;                       // private, enclosed in the IIFE
  return { inc: () => ++count, get: () => count }; // public API
})();

console.log(counter.inc(), counter.inc()); // 1 2
console.log(counter.get());                // 2
console.log(typeof count);                  // "undefined" — never leaked

// arrow IIFE — runs immediately, returns a value
const ts = (() => Date.now())();
console.log(typeof ts);                     // "number"

function debounce(fn, ms) { let t; return (...a) => { clearTimeout(t); t = setTimeout(() => fn(...a), ms); }; }
function throttle(fn, ms) { let last = 0; return (...a) => { const n = Date.now(); if (n - last >= ms) { last = n; fn(...a); } }; }

const d = debounce(() => console.log('debounced'), 50);
const t = throttle(() => console.log('throttled'), 50);
d(); d(); d();   // 'debounced' once (after it goes quiet)
t(); t(); t();   // 'throttled' once (immediately, rest ignored)
